import type { CheckoutCompletedEventPayload } from '@smartcart/shared-types';

/**
 * Domain-event publisher port (README §2.2 ACID directive, §2.8 Workflow 2).
 * Implemented by `BullMqEventPublisher`, which enqueues onto the
 * `analytics-profile-update` queue. Called ONLY after the checkout transaction
 * commits — a post-commit side effect that must never roll back the sale.
 */
export const EVENT_PUBLISHER = 'IEventPublisher';

export interface IEventPublisher {
  publish(event: CheckoutCompletedEventPayload): Promise<void>;
}
